use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities;
use chrono::Datelike;
use std::collections::BTreeMap;

pub struct InvoiceMonthlyCommand;

const BILLING_QUANTUM_SECONDS: i64 = 15 * 60;
const BILLING_MINIMUM_SECONDS: i64 = 30 * 60;

fn invoice_seconds(duration_seconds: i64) -> i64 {
    let rounded = ((duration_seconds + BILLING_QUANTUM_SECONDS - 1) / BILLING_QUANTUM_SECONDS)
        * BILLING_QUANTUM_SECONDS;
    rounded.max(BILLING_MINIMUM_SECONDS)
}

fn aggregate_months(entries: &[TimeEntry]) -> BTreeMap<String, i64> {
    let mut months = BTreeMap::new();

    for entry in entries {
        if !entry.billable || entry.stop.is_none() || entry.is_running() {
            continue;
        }

        let month = format!("{:04}-{:02}", entry.start.year(), entry.start.month());
        *months.entry(month).or_insert(0) += invoice_seconds(entry.duration);
    }

    months
}

impl InvoiceMonthlyCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = utilities::normalize_time_entry_list_filters(since, until)?;
        let entries = api_client
            .get_time_entries_filtered_minimal(since, until)
            .await?;
        let months = aggregate_months(&entries);

        if months.is_empty() {
            println!("(no data)");
            return Ok(());
        }

        let total: i64 = months.values().sum();
        for (month, seconds) in months {
            println!("{month}  {seconds}s");
        }
        println!("Total  {total}s");
        Ok(())
    }
}

